Send SMS.code:
// Send a single SMS via Twilio.
// state.references is populated with Twilio's API response.
sendSMS({
  // 1) Message body (max 1600 chars, billed per 160-char segment).
  body: `Hi ${$.data.name}, your appointment is confirmed.`,
  // 2) Your Twilio sending number, in E.164 format (e.g. +14155551212).
  from: $.configuration.fromNumber,
  // 3) Recipient, in E.164 format.
  to: $.data.phone,
});
